int main()
{
	int a1, a2, time=0;
	scanf("%d%d", &a1, &a2);
	while(a1>0 && a2>0)
	{
		if(a1==1 &&a2==1)
		{
			break;
		}
		if(a1>a2)
		{
			a1-=2;
			a2++;
			time++;
		}
		else
		{
			a2-=2;
			a1++;
			time++;
		}



	}
	printf("%d\n", time);











